// New: carry debug flag through pair-mode flow.
const { primaryId, secondaryId, slo, windowDays, now, cutoff, debug } = $json;

return [{
  json: {
    mode: 'pair',
    primaryId,
    secondaryId,
    slo: Number(slo),
    windowDays: Number(windowDays),
    now: Number(now),
    cutoff: Number(cutoff),
    debug: Boolean(debug),
    phase: 'primary',
    url: `https://api.statuscake.com/v1/uptime/${primaryId}/periods?limit=100`,
    primaryIntervals: [],
    secondaryIntervals: [],
    done: false,
  }
}];

function toEpoch(s) {
  return Math.floor(new Date(s).getTime() / 1000);
}

function clamp(x, lo, hi) {
  return Math.max(lo, Math.min(hi, x));
}

// New logic: collect clamped DOWN intervals for primary/secondary test streams.
const previousState =
  $runIndex > 0
    ? $items('Collect Pair + Next', 0, $runIndex - 1)[0].json
    : $items('Init Pair State')[0].json;

const state = {
  ...previousState,
  primaryIntervals: Array.isArray(previousState.primaryIntervals) ? [...previousState.primaryIntervals] : [],
  secondaryIntervals: Array.isArray(previousState.secondaryIntervals) ? [...previousState.secondaryIntervals] : [],
};

const resp = $json;
const data = resp.data || [];
const target = state.phase === 'primary' ? state.primaryIntervals : state.secondaryIntervals;

for (const p of data) {
  if (p.status !== 'down') continue;
  if (!p.created_at || !p.ended_at) continue;

  const s = toEpoch(p.created_at);
  const e = toEpoch(p.ended_at);
  const os = clamp(s, state.cutoff, state.now);
  const oe = clamp(e, state.cutoff, state.now);

  if (oe > os) {
    target.push({ start: os, end: oe });
  }
}

let oldest = state.now;
for (const p of data) {
  if (p.created_at) oldest = Math.min(oldest, toEpoch(p.created_at));
}

const nextUrl = resp.links?.next || null;
const phaseDone = (!nextUrl) || (oldest < state.cutoff);

if (!phaseDone) {
  state.url = nextUrl;
  state.done = false;
} else if (state.phase === 'primary') {
  state.phase = 'secondary';
  state.url = `https://api.statuscake.com/v1/uptime/${state.secondaryId}/periods?limit=100`;
  state.done = false;
} else {
  state.phase = 'complete';
  state.url = null;
  state.done = true;
}

return [{ json: state }];

// New: compute overlap and optionally emit overlap windows for debugging.
function normalize(intervals) {
  const sorted = [...intervals]
    .filter(i => Number(i.end) > Number(i.start))
    .map(i => ({ start: Number(i.start), end: Number(i.end) }))
    .sort((a, b) => a.start - b.start || a.end - b.end);

  const merged = [];
  for (const cur of sorted) {
    if (!merged.length || cur.start > merged[merged.length - 1].end) {
      merged.push({ ...cur });
    } else {
      merged[merged.length - 1].end = Math.max(merged[merged.length - 1].end, cur.end);
    }
  }
  return merged;
}

function toIso(sec) {
  return new Date(sec * 1000).toISOString();
}

const primary = normalize($json.primaryIntervals || []);
const secondary = normalize($json.secondaryIntervals || []);

let i = 0;
let j = 0;
let overlapSeconds = 0;
const overlapWindows = [];

while (i < primary.length && j < secondary.length) {
  const s = Math.max(primary[i].start, secondary[j].start);
  const e = Math.min(primary[i].end, secondary[j].end);

  if (e > s) {
    const dur = e - s;
    overlapSeconds += dur;

    if ($json.debug && overlapWindows.length < 300) {
      overlapWindows.push({
        start: s,
        end: e,
        startIso: toIso(s),
        endIso: toIso(e),
        seconds: dur,
      });
    }
  }

  if (primary[i].end <= secondary[j].end) i += 1;
  else j += 1;
}

const out = {
  slo: Number($json.slo),
  windowDays: Number($json.windowDays),
  totalDownMs: overlapSeconds * 1000,
};

if ($json.debug) {
  out.debug = {
    mode: "gold-ha",
    primaryId: $json.primaryId,
    secondaryId: $json.secondaryId,
    primaryIntervalCount: primary.length,
    secondaryIntervalCount: secondary.length,
    overlapSecondsTotal: overlapSeconds,
    overlapWindowCount: overlapWindows.length,
    overlapWindows,
    primarySample: primary.slice(0, 50).map(i => ({
      start: i.start,
      end: i.end,
      startIso: toIso(i.start),
      endIso: toIso(i.end),
      seconds: i.end - i.start,
    })),
    secondarySample: secondary.slice(0, 50).map(i => ({
      start: i.start,
      end: i.end,
      startIso: toIso(i.start),
      endIso: toIso(i.end),
      seconds: i.end - i.start,
    })),
  };
}

return [{ json: out }];

const query = $json.query || {};

const clusters = {
  silver:  { testId: "7719640", slo: 0.995 },
  emerald: { testId: "7719620", slo: 0.995 },
  "gold-ha": { primary: "7719621", secondary: "7719622", slo: 0.9995 },
};

const windowDays = Number(query.days || "30");
const now = Math.floor(Date.now() / 1000);
const cutoff = now - windowDays * 24 * 60 * 60;
const clusterKey = query.cluster ? String(query.cluster).toLowerCase() : null;

// New: opt-in debug output for overlap inspection.
const debug = ["1", "true", "yes"].includes(String(query.debug || "").toLowerCase());

if (clusterKey === "gold-ha") {
  const c = clusters["gold-ha"];
  return [{
    json: {
      mode: "pair",
      primaryId: c.primary,
      secondaryId: c.secondary,
      slo: Number(query.slo || c.slo),
      windowDays,
      now,
      cutoff,
      debug,
    }
  }];
}

// existing single-test behavior
let testId = query.test_id;
let slo = query.slo;

if (clusterKey && clusters[clusterKey]?.testId) {
  const c = clusters[clusterKey];
  testId = testId || c.testId;
  slo = slo || c.slo;
}

testId = String(testId || "7719640");
slo = Number(slo || "0.995");

return [{
  json: {
    mode: "single",
    testId,
    slo,
    windowDays,
    now,
    cutoff,
    url: `https://api.statuscake.com/v1/uptime/${testId}/periods?limit=100`,
    totalDownMs: 0,
    debug,
  }
}];

