const { slo, windowDays, totalDownMs } = $json;
const windowSeconds = windowDays * 24 * 60 * 60;

const allowedSeconds = Math.floor(windowSeconds * (1 - slo));
const usedSeconds = Math.floor(totalDownMs / 1000);
const remainingSeconds = Math.max(0, allowedSeconds - usedSeconds);
const remainingMinutes = +(remainingSeconds / 60).toFixed(2);

const out = {
  windowDays,
  slo,
  allowedSeconds,
  usedSeconds,
  remainingSeconds,
  remainingMinutes,
  downtimeUsedMs: totalDownMs
};

