if ($json.debug) {
  out.debug = {
    ...$json.debug,
    allowedSeconds,
    usedSeconds,
    remainingSeconds,
    remainingMinutes,
  };
}

return [{ json: out }];

const response = {
  data: [
    {
      timestamp: new Date().toISOString(),
      value: Number($json.remainingMinutes),
    },
  ],
};

// New: only include debug block when explicitly requested.
if ($json.debug) {
  response.debug = $json.debug;
}

return [{ json: response }];

